head.script:
scwin.grdFocusedRowIndex = null;
scwin.grdFocusedDeptCd = null;
scwin.bSearch = false;
scwin.isRowIndexReset = true;

scwin.initData = {
	"valInfo" : [
		{id : "setcscNm", maxLength : 40, mandatory : true},
		{id : "iemDivNm", maxLength : 40},
		{id : "iemDtlCtnt", maxByteLength : 4000},
	],
	"fileIdx" : ""
};

/**
 * 화면 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initScreen = function() {
	// 화면초기화 공통 함수 호출
	comLib.initForm($p, "ECSME1000000", {"initScreenCallback" : scwin.searchDatas});
};

/**
 * 화면 초기 데이터들을 조회한다.
 * @param
 * @return
 */
scwin.searchDatas = function() {
	// 조회조건 초기 설정
	scwin.initSearchParam();
	// 화면 데이터 조회
	scwin.btnInqire_onclick();
};

/**
 * 조회조건 초기화에 필요한 로직을 수행한다.
 * @param
 * @return
 */
scwin.initSearchParam = function() {
	var thsYear = utilLib.getCurrentDate("yyyy");
	var params = $p.getParameter("param");
	if (params && params.year) {
		thsYear = String(params.year);
	}
	dmaSearchParam.set("strtDt",  String(thsYear));
	// dmaSearchParam.set("endDt", utilLib.getCurrentDate("yyyy"));
	dmaSearchParam.set("basinCd", "ALL");
	dmaSearchParam.set("setcscCd", "ALL");
	dmaSearchParam.set("chrgDeptCd", "ALL");
};

/**
 * 화면 초기화에 필요한 로직을 수행한다. (조회 및 신규버튼 클릭 시)
 * @param
 * @return
 */
scwin.clearScreen = function() {
	grdEqpMngList.removeFocusedCell();
	if (scwin.isRowIndexReset) {
		scwin.grdFocusedRowIndex = null;
		scwin.grdFocusedDeptCd = null;
		scwin.bSearch = false;
	} else {
		scwin.isRowIndexReset = true;
	}
	// grdEqpMngList.removeFocusedCell();
	dltEqpMngList.reset();
	dmaEqpMng.setEmpty();

	// 상세보기 첨부파일 초기화
	scwin.atchflFormReset();
	scwin.trDtlDisplay(false);
};

/**
 * 조회 버튼 클릭 이벤트
 * @param
 * @return
 */
scwin.btnInqire_onclick = function() {
	scwin.clearScreen();
	scwin.inqire();
};

/**
 * 조회조건에 맞게 data를 조회한다.
 * @param
 * @return
 */
scwin.inqire = function() {
	var strtDt = dmaSearchParam.get("strtDt");
	var ecsBasinDivCd = dmaSearchParam.get("basinCd");
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = dmaSearchParam.get("chrgDeptCd");

	if (String(strtDt).length != 4) {
		// 조회기간이 올바르지 않습니다.
		alert(utilLib.getMessage("ECS.INFO.00011")[0]);
		return;
	}

	var queryString = `?strtDt=${strtDt}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var option = {
		action : "me/mntmng/retrieve-mntmng.do"
			+ queryString,
		method : "get",
		resData : dltOperAmtList,
		success : "scwin.inqireCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 조회 CallBack 실행한다.
 * @param
 * @return
 */
scwin.inqireCallback = function() {
	spnOperAmtLblTotalRow.setValue(dltOperAmtList.getRowCount());
	spnEqpMngLblTotalRow.setValue(dltEqpMngList.getRowCount());

	if (scwin.bSearch) {
		scwin.grdFocusedRowIndex = grdOperAmtList.getAllJSON().findIndex(obj => obj.requstDeptCd == scwin.grdFocusedDeptCd);
		scwin.grdFocusedDeptCd = null;
		scwin.bSearch = false;
		grdOperAmtList.setFocusedCell(scwin.grdFocusedRowIndex, 0);
		scwin.grdOperAmtList_onrowindexchange(scwin.grdFocusedRowIndex);
		scwin.clearScreen();
	} else {
		if (scwin.grdFocusedRowIndex != null) {
			grdEqpMngList.setFocusedCell(scwin.grdFocusedRowIndex, 0);
		} else {
			// 화면 오픈과 동시에 상세보기 항목은 초기화 한다.
			scwin.clearScreen();
		}
	}
};

/**
 * 신규버튼 클릭시 dataMap을 초기화 한다.
 * @param
 * @return
scwin.btnNew_onclick = function() {
	scwin.clearScreen();
	scwin.setModalDisabled(dmaEqpMng.getJSON());
	ecsLib.validateInput(grpDtl, scwin.initData.valInfo, true);
};
*/

/**
 * 그리드뷰의 내용을 수정/저장 버튼 이벤트.
 * @param
 * @return
 */
scwin.btnSave_onclick = function() {
	var dmaData = dmaEqpMng.getJSON();
	var file1 = ibxAtchFile1.getValue();
	var file2 = ibxAtchFile2.getValue();

	if (dltEqpMngList.getModifiedJSON().cntrctNo == "") {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}
	// 수정 사항 없을 때, 첨부파일 없을 때
	if (dltEqpMngList.getModifiedData() == "" && file1 == dmaData.lrgeChckAtchflNm && file2 == dmaData.dcompChckAtchflNm) {
		// 처리할 데이터가 없습니다.
		comLib.alert($p, utilLib.getMessage("SCM.INFO.00304"));
		return;
	}
	// 발전원을 선택해주세요.
	for (data of dltEqpMngList.getModifiedJSON()) {
		// 발전원을 선택하면 ecsSetcscDivCd가 아니라 setcscNm에 값이 들어가서 조건을 setcscNm로 수정함_231205
		if (data.setcscNm == "") {
			comLib.alert($p, utilLib.getMessage("ECS.INFO.00202"));
			return;
		}
	}
	// 수정 사항 있을 때
	if (utilLib.validateGridView(grdEqpMngList, scwin.initData.valInfo, null, {"type":"modify"})) {
		var columnList = scwin.initData.valInfo.filter(obj => obj).flatMap(obj => obj.id);
		var addCount = 0;
		var modifyCount = 0;
		var delCount = 0;
		dltEqpMngList.getModifiedJSON().forEach(obj => {
			var rowStatus = obj.rowStatus;
			switch(rowStatus) {
				case "C":
					// 추가
					addCount++;
					break;
				case "U":
					// 수정
					modifyCount++;
					break;
				case "E":
					// 삭제
					delCount++;
					break;
				default:
					break;
			}
		});
		var extendMsg = ecsLib.extendCustomSaveMsg(addCount, modifyCount, delCount);
		// 변경된 내역이 있습니다.\n저장 하시겠습니까? \n수정사유를 입력하세요.
		ecsLib.saveRsn($p, `${dltEqpMngList.getID()}.updtRsn`, utilLib.getMessage("SCM.INFO.00239")[0] + extendMsg, "scwin.saveConfirmCallback");
	}
};

/**
 * 수정/저장 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.saveConfirmCallback = function() {
	var idx = grdOperAmtList.getFocusedRowIndex();
	scwin.grdFocusedDeptCd = grdOperAmtList.getAllJSON()[idx].requstDeptCd;
	scwin.fileChecksUpload();
};

// 첨부파일 여부 확인 및 임시 저장
scwin.fileChecksUpload = function() {
	var rowIdx = grdEqpMngList.getFocusedRowIndex();
	// rowIdx가 Focused 안 되어 있을 때_231207
	if (rowIdx == "-1") {
		rowIdx = Number("0");
		var dltRowData = dltEqpMngList.getAllJSON()[rowIdx];
	} else {
		var dltRowData = dltEqpMngList.getAllJSON()[rowIdx];
	}
	var dmaData = dmaEqpMng.getJSON();
	var file1 = ibxAtchFile1.getValue();
	var file2 = ibxAtchFile2.getValue();

	// 첨부파일이 있는 경우
	if (mpdSinglFile1.getFileCount() > 0) {
		if (dltRowData.atchflId == "") {
			var sysDivCd = comLib.getSysDivCd();
			var markanyTime = $p.getCurrentServerDate("yyyyMMddHHmmssSSS");
			dltRowData.atchflId = sysDivCd + markanyTime.substr(2);
			dltEqpMngList.setRowJSON(rowIdx, dltRowData, true);
		}
		var file = dltFile1.getAllJSON()[0];
		file.atchflId = dltRowData.atchflId;
		// file.docClsCd = "ECS300";
		dltFile1.setRowJSON(0, file, true);
		mpdSinglFile1.startUpload();
	} else if (file1 == "") {
		// 첨부파일이 없거나 지워진 경우 data set
		dltRowData.lrgeChckAtchflNm = "";
		dltRowData.lrgeChckAtchFlpth = "";
		dltEqpMngList.setRowJSON(rowIdx, dltRowData, true);
	}

	if (mpdSinglFile2.getFileCount() > 0) {
		if (dltRowData.atchflId == "") {
			var sysDivCd = comLib.getSysDivCd();
			var markanyTime = $p.getCurrentServerDate("yyyyMMddHHmmssSSS");
			dltRowData.atchflId = sysDivCd + markanyTime.substr(2);
			dltEqpMngList.setRowJSON(rowIdx, dltRowData, true);
		}
		var file = dltFile2.getAllJSON()[0];
		file.atchflId = dltRowData.atchflId;
		// file.docClsCd = "ECS300";
		dltFile2.setRowJSON(0, file, true);
		mpdSinglFile2.startUpload();
	} else if (file2 == "") {
		dltRowData.dcompChckAtchflNm = "";
		dltRowData.dcompChckAtchFlpth = "";
		dltEqpMngList.setRowJSON(rowIdx, dltRowData, true);
	}

	// 첨부파일이 없는 경우
	if (mpdSinglFile1.getFileCount() == 0 && mpdSinglFile2.getFileCount() == 0) {
		scwin.grdModifiedSave();
	}
};

/**
 * 그리드뷰의 수정내용을 수정/저장한다.
 * @param
 * @return
 */
scwin.grdModifiedSave = function() {
	var requestData = {};
	requestData.dltEqpMngList = dltEqpMngList.getModifiedJSON();
	requestData.dltFile1 = dltFile1.getAllJSON();
	requestData.dltFile2 = dltFile2.getAllJSON();

	// 발전원, 정산구분 데이터 수정을 안할 시 발전원, 정산구분 코드가 코드네임으로 나오는 부분 코드로 수정
	requestData.dltEqpMngList.forEach(obj => {
		var item = dltAutoCondition4.getAllJSON().find(search => search.cmmnCdNm == obj.setcscNm);
		var item2 = dltAutoCondition3.getAllJSON().find(search => search.cmmnCdNm == obj.iemDivNm);

		if (item && item2) {
			obj.setcscNm = item.cmmnCd;
			obj.iemDivNm = item2.cmmnCd;
		} else if (item) {
			obj.setcscNm = item.cmmnCd;
		} else if (item2) {
			obj.iemDivNm = item2.cmmnCd;
		}
	});

	var option = {
		action : "me/mntmng/process-mntmng.do",
		reqData : requestData,
		success : "scwin.saveMsgCallback",
		savedToken : true,
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 수정/저장 CallBack 실행한다.
 * @param <Object> res
 * @return
 */
scwin.saveMsgCallback = function(res) {
	comLib.alert($p, res.message.code_name);

	scwin.bSearch = true;
	scwin.isRowIndexReset = false;
	scwin.inqire();
};

/**
 * 작업중이던 내용을 취소한다.
 * @param
 * @return
 */
scwin.btnCancl_onclick = function() {
	// 저장하지 않고 종료하시겠습니까?.
	comLib.confirm($p, utilLib.getMessage("SCM.INFO.00291")[0], "scwin.cancelConfirmCallback");
};

/**
 * 취소 ComfirmCallBack 실행한다.
 * @param
 * @return
 */
scwin.cancelConfirmCallback = function() {
	scwin.inqire();
};

/**
 * 조회박스 선택별 값을 세팅한다.
 * @param
 * @return
 */
scwin.acbBasin_onviewchange = function(info) {
	var ecsBasinDivCd = info.newValue;
	dmaSearchParam.set("basinCd", ecsBasinDivCd);

	var queryString = `ecsBasinDivCd=${ecsBasinDivCd}`;

	var option = {
		action : "zz/cmmn/retrieve-hrm-dept.do?"
			+ queryString,
		method : "get",
		resData : dltAutoCondition2,
		success : "",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
	dmaSearchParam.set("chrgDeptCd", "ALL");
};

scwin.acbSetcsc_onviewchange = function(info) {
	grdOperAmtList.removeFocusedCell();
	scwin.grdFocusedRowIndex = null;
	dmaSearchParam.set("setcscCd", info.newValue);
};

scwin.acbChrgDept_onviewchange = function(info) {
	if (info.newSelectedIndex > 0) {
		var data = dltAutoCondition2.getRowJSON(info.newSelectedIndex - 1);
		// dmaSearchParam.set("chrgDeptCd", data.upperCmmnCd.slice(-4));
		dmaSearchParam.set("chrgDeptCd", data.upperCmmnCd);
	} else {
		dmaSearchParam.set("chrgDeptCd", "ALL");
	}
};

/**
 * 운영금액 클릭시 설비관리 상세이력 데이터 조회 이벤트
 * @param
 * @return
 */
scwin.grdOperAmtList_onrowindexchange = function(row, col) {
	scwin.atchflFormReset();
	scwin.trDtlDisplay(false);
	dmaEqpMng.setEmpty();
	scwin.grdFocusedRowIndex = row;

	// 그리드 데이터 조회
	var rowJSON = dltOperAmtList.getRowJSON(row);
	var strtDate = rowJSON.year;
	var ecsBasinDivCd = rowJSON.basinNm;
	var ecsSetcscDivCd = dmaSearchParam.get("setcscCd");
	var ecsChrgDeptId = rowJSON.requstDeptCd;

	if (!strtDate || !ecsChrgDeptId) {
		return;
	}

	var queryString = `?strtDt=${strtDate}`;
	queryString += `&ecsBasinDivCd=${ecsBasinDivCd}`;
	queryString += `&ecsSetcscDivCd=${ecsSetcscDivCd}`;
	queryString += `&ecsChrgDeptId=${ecsChrgDeptId}`;

	var option = {
		action : "me/mntmng/retrieve-mntmng-hist.do"
			+ queryString,
		method : "get",
		resData : dltEqpMngList,
		success : "scwin.inqireEqpMngCallback",
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

/**
 * 운영금액 클릭시 설비관리 상세이력 inqireEqpMngCallback 실행한다.
 * @param
 * @return
 */
scwin.inqireEqpMngCallback = function() {
	spnEqpMngLblTotalRow.setValue(dltEqpMngList.getRowCount());

	// 엑셀 업로드 후 빈 데이터에 다시 데이터 추가 위해 생성_231108
	var dltEqpMngListData = dltEqpMngList.getAllJSON();
	scwin.dataSet = [];
	for (var idx = 0; idx < dltEqpMngList.getRowCount(); idx++) {
		if (dltEqpMngListData[idx].cntrctNo) {
			var data = {}
			data.row = idx;
			data.cntrctNo = dltEqpMngListData[idx].cntrctNo;
			data.cntrctDivNm = dltEqpMngListData[idx].cntrctDivNm;
			data.newOrdyrDivNm = dltEqpMngListData[idx].newOrdyrDivNm;
			data.rqstrNm = dltEqpMngListData[idx].rqstrNm;
			data.cntrctDeptNm = dltEqpMngListData[idx].cntrctDeptNm;
			data.rqstrEmpno = dltEqpMngListData[idx].rqstrEmpno;
			data.reltDoc = dltEqpMngListData[idx].reltDoc;
			data.ctrCsct = dltEqpMngListData[idx].ctrCsct;
			data.competam = dltEqpMngListData[idx].competam;
			scwin.dataSet.push(data);
		}
	}
};

/**
 * 설비관리 상세이력 row 선택시 해당 내용을 상세보기로 표출한다.
 * @param <Int> row
 * @param <Int> oldRow
 * @return
 */
scwin.grdEqpMngList_onrowindexchange = function(row, oldRow) {
	scwin.atchflFormReset();
	scwin.trDtlDisplay(true);
	var rowData = dltEqpMngList.getRowJSON(row);

	// 상세보기에 발전원, 정산구분 네임 표시
	if (rowData.setcscNm && rowData.iemDivNm && rowData.rowStatus == "U") {
		var dlt = dltAutoCondition4.getAllJSON();
		var dlt2 = dltAutoCondition3.getAllJSON();
		var ecsSetcscDivCd = rowData.setcscNm;
		var iemDivCd = rowData.iemDivNm;
		var setcscNm = dlt.find(obj => obj.cmmnCd == ecsSetcscDivCd) ? dlt.find(obj => obj.cmmnCd == ecsSetcscDivCd).cmmnCdNm : dlt.find(obj => obj.cmmnCdNm == ecsSetcscDivCd).cmmnCdNm;
		var iemDivNm = dlt2.find(obj => obj.cmmnCd == iemDivCd) ? dlt2.find(obj => obj.cmmnCd == iemDivCd).cmmnCdNm : dlt2.find(obj => obj.cmmnCdNm == iemDivCd).cmmnCdNm;

		rowData.setcscNm = setcscNm;
		rowData.iemDivNm = iemDivNm;
	} else if (rowData.setcscNm && rowData.rowStatus == "U") {
		var dlt = dltAutoCondition4.getAllJSON();
		var ecsSetcscDivCd = rowData.setcscNm;
		var setcscNm = dlt.find(obj => obj.cmmnCd == ecsSetcscDivCd) ? dlt.find(obj => obj.cmmnCd == ecsSetcscDivCd).cmmnCdNm : dlt.find(obj => obj.cmmnCdNm == ecsSetcscDivCd).cmmnCdNm;

		rowData.setcscNm = setcscNm;
	} else if (rowData.iemDivNm && rowData.rowStatus == "U") {
		var dlt2 = dltAutoCondition3.getAllJSON();
		var iemDivCd = rowData.iemDivNm;
		var iemDivNm = dlt2.find(obj => obj.cmmnCd == iemDivCd) ? dlt2.find(obj => obj.cmmnCd == iemDivCd).cmmnCdNm : dlt2.find(obj => obj.cmmnCdNm == iemDivCd).cmmnCdNm;

		rowData.iemDivNm = iemDivNm;
	}

	if (rowData.reltDoc) {
		var emtDoc = "<span></span>";
		var docNum = 1;
		if (rowData.ordgDrftId) {
			emtDoc += `<a class="w2anchor2 doc-list" data-apprid="${rowData.ordgDrftId}" href="javascript:void(null);" style="color: #0077E1; text-decoration-line: underline;">${docNum++}) 발주기안문서</a><br/>`;
		}
		if (rowData.scsbidDrftId) {
			emtDoc += `<a class="w2anchor2 doc-list" data-apprid="${rowData.scsbidDrftId}" href="javascript:void(null);" style="color: #0077E1; text-decoration-line: underline;">${docNum++}) 낙찰기안문서</a><br/>`;
		}
		if (rowData.cntrctDrftId) {
			emtDoc += `<a class="w2anchor2 doc-list" data-apprid="${rowData.cntrctDrftId}" href="javascript:void(null);" style="color: #0077E1; text-decoration-line: underline;">${docNum++}) 계약기안문서</a>`;
		}
		rowData.reltDoc = emtDoc;
	}
	dmaEqpMng.setJSON(rowData);

	// 첨부파일 세팅
	ibxAtchFile1.setValue(rowData.lrgeChckAtchflNm);
	ibxAtchFile2.setValue(rowData.dcompChckAtchflNm);

	document.querySelectorAll(`#${spnReltDoc.getID()} .doc-list`).forEach(emt => {
		emt.addEventListener("click", function(e) {
			var apprId = e.target.getAttribute("data-apprid");
			var url = `${ecsLib.DOC_VIEWER_URL}?APPRID=${apprId}`;
			window.open(url, "전자문서", "toolbar=no,menubar=yes,location=no,directories=yes,status=yes,scrollbars=yes,resizable=yes,width=800,height=600,fullscreen=yes");
		});
	});

	/*
	if (rowData.cntrctRequstDeYn == "Y") {
		spnCompetDeLabel.setLabel("계약요청일");
	} else {
		spnCompetDeLabel.setLabel("준공일");
	}
	*/
	// ecsLib.validateInput(grpDtl, scwin.initData.valInfo, true);
};

scwin.grdEqpMngList_onafteredit = function(row,col,value) {
	ecsLib.updateGridViewFontColor(grdEqpMngList, row, col);
};

/**
 * 모달 버튼 숨김 기능 처리
 * @param json : dma.getJSON()
 * @return
 */
scwin.setModalDisabled = function(json) {
	// 모달 버튼 숨김 기능 처리
	if (json.ordgTit != "null" && json.ordgTit != "") {
		btnModal.setStyle("display", "none");
		btnEditModal.setStyle("display", "inline-block");
	} else if (json.ordgTit == "") {
		btnModal.setStyle("display", "inline-block");
		btnEditModal.setStyle("display", "none");
	}
};

