/**
 * 관련문서 조회 팝업을 오픈한다.
 * @param
 * @return
 */
scwin.docPopupOepn = function() {
	var queryString = `?usrId=${WebSquare.session.getAttribute("usrEmpno")}`;
	var option = {
		action : "zz/cmmn/enc-emp-no.do"
			+ queryString,
		method : "get",
		success : function(res) {
			if (!res.data.EMPNO || !dmaEqpMng.getJSON().reltDoc.split(",")[0]) {
				return;
			}
			var url = "https://oasis.[BASE_DOMAIN]/custom/DocViewer.jsp?crypt=1";
			url += `&APPRID=${dmaEqpMng.getJSON().reltDoc.split(",")[0]}`;
			url += `&EMPNO=${res.data.EMPNO}`;
			window.open(url, "전자문서", "toolbar=no,menubar=yes,location=no,directories=yes,status=yes,scrollbars=yes,resizable=yes,width=800,height=500,fullscreen=yes");
		},
		isShowMeg : false
	};
	ajaxLib.executeAjax($p, option);
};

