/**
 * 엑셀 내용을 그리드에 저장한다.
 * @return
 */
scwin.grdEqpMngList_onfilereadend = function(value) {
	var dltData = dltEqpMngList.getAllJSON();
	var dltAuto4 = dltAutoCondition4.getAllJSON();

	// 업로드 후 빈 데이터 값에 기존 데이터 재설정 set JSON
	var dltData = dltEqpMngList.getAllJSON();
	for (data of scwin.dataSet) {
		tempData = dltData[data.row];
		tempData.cntrctNo = data.cntrctNo;
		tempData.cntrctDivNm = data.cntrctDivNm;
		tempData.newOrdyrDivNm = data.newOrdyrDivNm;
		tempData.rqstrNm = data.rqstrNm;
		tempData.cntrctDeptNm = data.cntrctDeptNm;
		tempData.rqstrEmpno = data.rqstrEmpno;
		tempData.reltDoc = data.reltDoc;
		tempData.ctrCsct = data.ctrCsct;
		tempData.competam = data.competam;
		dltData[data.row] = tempData;
	}
	dltEqpMngList.setJSON(dltData);
	// rowStatus 상태값 변경
	for (var idx = 0; idx < dltData.length; idx++) {
		dltEqpMngList.modifyRowStatus(idx, "C");
	}
};

