/**
* 첨부 파일 임시저장후 콜백(전송)
* @param
* @return
*/
scwin.mpdSinglFile1_ondone = function(data) {
	var rowIdx = grdEqpMngList.getFocusedRowIndex();
	var dltRowData = dltEqpMngList.getAllJSON()[rowIdx];

	// scwin.grdModifiedSave();
	// WebSquare.layer.hideProcessMessage();	// 화면 blocking 해제
	// 첨부파일정보 셋팅
	var rtnYn = fileLib.dataListSetting(dltFile1, data);
	if (rtnYn) {
		//	comLib.confirm($p.parent().$p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveConfirmCallback");
		// comLib.confirm($p, utilLib.getMessage("SCM.INFO.00321"), "scwin.saveConfirmCallback");
		dltRowData.lrgeChckAtchflNm = data[0].localFile;
		// dltRowData.lrgeChckAtchFlpth = data[0].file;
		dltRowData.lrgeChckAtchFlpth = dltFile1.getAllJSON()[0].atchflId;
		dltEqpMngList.setRowJSON(rowIdx, dltRowData, true);
		if (mpdSinglFile2.getFileCount() > 0) {
			if (ibxBigFileStatus2.getTitle() == "100%") {
				scwin.grdModifiedSave();
			}
		} else {
			scwin.grdModifiedSave();
		}
	}
};

