		};
	} else {
		var dataObj = {
			strtDt : grdOperAmtList.getAllJSON()[scwin.grdFocusedRowIndex].year,
			deptCd : grdOperAmtList.getAllJSON()[scwin.grdFocusedRowIndex].requstDeptCd,
