		popupName : "SAP 점검정비 상세이력 목록 조회",
		width : 1200,
		height : 710,
		top : 150,
		left : 0,
		modal : true,
		closeAction : "",
		popupParam : dataObj
	};
	comLib.openPopup($p, "ECSME1100000", url, options);
};

/**
* 첨부파일 다운로드
* @param event
* @return 첨부파일
*/
scwin.ibxAtchFile_onclick = function(e) {
	var atchflId = "";
	var fileSeq = 0;
	if (this.id.substr(-1) == 1) {
		atchflId = dmaEqpMng.getJSON().lrgeChckAtchFlpth + "01";
	}
	if (this.id.substr(-1) == 2) {
		atchflId = dmaEqpMng.getJSON().dcompChckAtchFlpth + "02";
	}

	if (atchflId != null && atchflId != "") {
		var dmaFile = {
			"atchflId" : atchflId,
			"fileSeq" : fileSeq
		};
		var xmlValue = JSON.stringify(dmaFile);
		$w.download("/sc/file/downloadAtchFileOne.do", xmlValue, "get");
	}
};
